const email = $input.first().json;

const from = email.from?.text || email.from || '';
const to = email.to?.text || email.to || '';
const subject = email.subject || '(sans objet)';
const date = email.date || new Date().toISOString();
const textPlain = (email.text || '').substring(0, 1000);
const hasAttachments = (email.attachments || []).length > 0;

return [{ json: {
  from,
  to,
  subject,
  date,
  textPlain,
  hasAttachments,
  tenantId: '{{ TENANT_ID }}',
  action: 'received'
} }];

